    23→    description: t(
    24→      'stat.add-standard-data-reduce-options.description-show',
    25→      'Calculate a single value per column or series or show each row'
    26→    ),
    27→    settings: {
    28→      options: [
    29→        { value: false, label: t('stat.add-standard-data-reduce-options.show-options.label-calculate', 'Calculate') },
    30→        { value: true, label: t('stat.add-standard-data-reduce-options.show-options.label-all-values', 'All values') },
    31→      ],
    32→    },
    33→    category: valueOptionsCategory,
    34→    defaultValue: false,
    35→  });
    36→
    37→  builder.addNumberInput({
    38→    path: 'reduceOptions.limit',
    39→    name: t('stat.add-standard-data-reduce-options.name-limit', 'Limit'),
    40→    description: t('stat.add-standard-data-reduce-options.description-limit', 'Max number of rows to display'),
    41→    category: valueOptionsCategory,
    42→    settings: {
    43→      placeholder: '25',
    44→      integer: true,
    45→      min: 1,
    46→      max: 5000,
    47→    },
    48→    showIf: (options) => options.reduceOptions.values === true,
    49→  });
    50→
    51→  builder.addCustomEditor({
    52→    id: 'reduceOptions.calcs',
    53→    path: 'reduceOptions.calcs',
    54→    name: t('stat.add-standard-data-reduce-options.name-calculation', 'Calculation'),
    55→    description: t(
    56→      'stat.add-standard-data-reduce-options.description-calculation',
    57→      'Choose a reducer function / calculation'
    58→    ),
    59→    category: valueOptionsCategory,
    60→    editor: standardEditorsRegistry.get('stats-picker').editor,
    61→    // TODO: Get ReducerID from generated schema one day?
    62→    defaultValue: [ReducerID.lastNotNull],
    63→    // Hides it when all values mode is on
    64→    showIf: (currentConfig) => currentConfig.reduceOptions.values === false,
    65→  });
    66→
    67→  if (includeFieldMatcher) {
    68→    builder.addSelect({
    69→      path: 'reduceOptions.fields',
    70→      name: t('stat.add-standard-data-reduce-options.name-fields', 'Fields'),
    71→      description: t(
