    83→              label: t('stat.add-standard-data-reduce-options.fields-options.label-numeric-fields', 'Numeric Fields'),
    84→            },
    85→            {
    86→              value: '/.*/',
    87→              label: t('stat.add-standard-data-reduce-options.fields-options.label-all-fields', 'All Fields'),
    88→            },
    89→          ];
    90→          if (context && context.data) {
