   166→/**
   167→ * @returns an object with a key for each selected stat
   168→ * NOTE: This will also modify the 'field.state' object,
   169→ * leaving values in a cache until cleared.
   170→ */
   171→export function reduceField(options: ReduceFieldOptions): FieldCalcs {
   172→  const { field, reducers } = options;
   173→
   174→  if (!field || !reducers || reducers.length < 1) {
   175→    return {};
   176→  }
   177→
   178→  if (field.state?.calcs) {
   179→    // Find the values we need to calculate
   180→    const missing: string[] = [];
   181→    for (const s of reducers) {
   182→      if (!field.state.calcs.hasOwnProperty(s)) {
   183→        missing.push(s);
   184→      }
   185→    }
   186→    if (missing.length < 1) {
   187→      return {
   188→        ...field.state.calcs,
   189→      };
   190→    }
   191→  }
   192→  if (!field.state) {
   193→    field.state = {};
   194→  }
   195→
   196→  const queue = fieldReducers.list(reducers);
   197→
   198→  // Return early for empty series
   199→  // This lets the concrete implementations assume at least one row
   200→  const data = field.values;
   201→  if (data && data.length < 1) {
   202→    const calcs: FieldCalcs = { ...field.state.calcs };
   203→    for (const reducer of queue) {
   204→      calcs[reducer.id] = reducer.emptyInputResult !== null ? reducer.emptyInputResult : null;
   205→    }
   206→    return (field.state.calcs = calcs);
   207→  }
   208→
   209→  // Default to Ignore for nullValueMode.
   210→  const { nullValueMode = NullValueMode.Ignore } = field.config;
   211→
   212→  const ignoreNulls = nullValueMode === NullValueMode.Ignore;
   213→  const nullAsZero = nullValueMode === NullValueMode.AsZero;
   214→
   215→  // Avoid calculating all the standard stats if possible
   216→  if (queue.length === 1 && queue[0].reduce) {
   217→    const values = queue[0].reduce(field, ignoreNulls, nullAsZero);
   218→    field.state.calcs = {
   219→      ...field.state.calcs,
   220→      ...values,
   221→    };
   222→    return values;
   223→  }
   224→
   225→  // For now everything can use the standard stats
   226→  let values = doStandardCalcs(field, ignoreNulls, nullAsZero);
   227→
   228→  for (const reducer of queue) {
   229→    if (!values.hasOwnProperty(reducer.id) && reducer.reduce) {
   230→      values = {
   231→        ...values,
   232→        ...reducer.reduce(field, ignoreNulls, nullAsZero),
   233→      };
   234→    }
   235→  }
   236→
   237→  field.state.calcs = {
   238→    ...field.state.calcs,
   239→    ...values,
   240→  };
   241→  return values;
   242→}
