   440→// This `Array.from` will build an array of elements from 1 to 99
   441→const buildPercentileReducers = (percentiles = [...Array.from({ length: 99 }, (_, i) => i + 1)]) => {
   442→  const percentileReducers: FieldReducerInfo[] = [];
   443→  const nth = (n: number) =>
   444→    n > 3 && n < 21 ? 'th' : n % 10 === 1 ? 'st' : n % 10 === 2 ? 'nd' : n % 10 === 3 ? 'rd' : 'th';
   445→
   446→  percentiles.forEach((p) => {
   447→    const percentile = p / 100;
   448→    const id = `p${p}`;
   449→    const name = `${p}${nth(p)} %`;
   450→    const description = `${p}${nth(p)} percentile value`;
   451→
   452→    percentileReducers.push({
   453→      id: id,
   454→      name: name,
   455→      description: description,
   456→      standard: false,
   457→      reduce: (field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs => {
   458→        return { [id]: calculatePercentile(field, percentile, ignoreNulls, nullAsZero) };
   459→      },
   460→      preservesUnits: true,
   461→    });
   462→  });
   463→  return percentileReducers;
   464→};
